29	NPY_NO_EXPORT int
30	PyArray_Resize_int(PyArrayObject *self, PyArray_Dims *newshape, int refcheck)
31	{
32	    npy_intp oldnbytes, newnbytes;
33	    npy_intp oldsize, newsize;
34	    int new_nd=newshape->len, k, elsize;
35	    npy_intp* new_dimensions=newshape->ptr;
36	    npy_intp new_strides[NPY_MAXDIMS];
37	    npy_intp *dimptr;
38	    char *new_data;
39	
40	    if (!PyArray_ISONESEGMENT(self)) {
41	        PyErr_SetString(PyExc_ValueError,
42	                "resize only works on single-segment arrays");
43	        return -1;
44	    }
45	
46	    /* Compute total size of old and new arrays. The new size might overflow */
47	    oldsize = PyArray_SIZE(self);
48	    newsize = 1;
49	    for(k = 0; k < new_nd; k++) {
50	        if (new_dimensions[k] == 0) {
51	            newsize = 0;
52	            break;
53	        }
54	        if (new_dimensions[k] < 0) {
55	            PyErr_SetString(PyExc_ValueError,
56	                    "negative dimensions not allowed");
57	            return -1;
58	        }
59	        if (npy_mul_sizes_with_overflow(&newsize, newsize, new_dimensions[k])) {
60	            PyErr_NoMemory();
61	            return -1;
62	        }
63	    }
64	
65	    /* Convert to number of bytes. The new count might overflow */
66	    elsize = PyArray_ITEMSIZE(self);
67	    oldnbytes = oldsize * elsize;
68	    if (npy_mul_sizes_with_overflow(&newnbytes, newsize, elsize)) {
69	        PyErr_NoMemory();
70	        return -1;
71	    }
72	
73	    if (oldnbytes != newnbytes) {
74	        if (!(PyArray_FLAGS(self) & NPY_ARRAY_OWNDATA)) {
75	            PyErr_SetString(PyExc_ValueError,
76	                    "cannot resize this array: it does not own its data");
77	            return -1;
78	        }
79	
80	        static const char *msg =
81	                "cannot resize an array that references or is referenced\n"
82	                "by another object in this way.\n"
83	                "Use the np.resize function to get a new resized copy or\n "
84	                "set refcheck=False to disable this check";
85	        if (PyArray_BASE(self) != NULL
86	              || (((PyArrayObject_fields *)self)->weakreflist != NULL)) {
87	            PyErr_SetString(PyExc_ValueError, msg);
88	            return -1;
89	        }
90	        if (refcheck) {
91	#if PY_VERSION_HEX >= 0x030E00B0
92	            // Python 3.14 changed reference counting semantics for function-
93	            // local variables. There is no way to tell if the calling function
94	            // has been optimized (because it might be implemented in C or Cython)
95	            //
96	            // Instead, warn if the refcount is exactly 2 that this might be a
97	            // false positive
98	            if (!PyUnstable_Object_IsUniquelyReferenced((PyObject *)self)) {
99	                if (Py_REFCNT(self) == 2) {
100	                    PyErr_SetString(
101	                            PyExc_ValueError,
102	                            "cannot resize an array that may be referenced "
103	                            "by another object.\n"
104	                            "It is possible that this is a false positive.\n"
105	                            "If you are sure that the array is uniquely referenced, "
106	                            "set refcheck=False.");
107	                    return -1;
108	                }
109	#else
110	            if (Py_REFCNT(self) > 2) {
111	#endif
112	                PyErr_SetString(PyExc_ValueError, msg);
113	                return -1;
114	            }
115	        }
116	        /* Reallocate space if needed - allocating 0 is forbidden */
117	        PyObject *handler = PyArray_HANDLER(self);
118	        if (handler == NULL) {
119	            /* This can happen if someone arbitrarily sets NPY_ARRAY_OWNDATA */
120	            PyErr_SetString(PyExc_RuntimeError,
121	                            "no memory handler found but OWNDATA flag set");
122	            return -1;
123	        }
124	        if (newnbytes < oldnbytes) {
125	            /* Clear now removed data (if dtype has references) */
126	            if (PyArray_ClearBuffer(
127	                    PyArray_DESCR(self), PyArray_BYTES(self) + newnbytes,
128	                    elsize, oldsize-newsize, PyArray_ISALIGNED(self)) < 0) {
129	                return -1;
130	            }
131	        }
132	
133	        new_data = PyDataMem_UserRENEW(PyArray_DATA(self),
134	                                       newnbytes == 0 ? 1 : newnbytes,
135	                                       handler);
136	        if (new_data == NULL) {
137	            PyErr_SetString(PyExc_MemoryError,
138	                    "cannot allocate memory for array");
139	            return -1;
140	        }
141	        ((PyArrayObject_fields *)self)->data = new_data;
142	
143	        if (newnbytes > oldnbytes && PyArray_ISWRITEABLE(self)) {
144	            /* Fill new memory with zeros (PyLong zero for object arrays) */
145	            npy_intp stride = elsize;
146	            npy_intp size = newsize - oldsize;
147	            char *data = PyArray_BYTES(self) + oldnbytes;
148	            int aligned = PyArray_ISALIGNED(self);
149	            if (PyArray_ZeroContiguousBuffer(PyArray_DESCR(self), data,
150	                                            stride, size, aligned) < 0) {
151	                return -1;
152	            }
153	        }
154	    }
155	
156	    if (new_nd > 0) {
157	        if (PyArray_NDIM(self) != new_nd) {
158	            /* Different number of dimensions. */
159	            ((PyArrayObject_fields *)self)->nd = new_nd;
160	            /* Need new dimensions and strides arrays */
161	            dimptr = PyDimMem_RENEW(PyArray_DIMS(self), 3*new_nd);
162	            if (dimptr == NULL) {
163	                PyErr_SetString(PyExc_MemoryError,
164	                                "cannot allocate memory for array");
165	                return -1;
166	            }
167	            ((PyArrayObject_fields *)self)->dimensions = dimptr;
168	            ((PyArrayObject_fields *)self)->strides = dimptr + new_nd;
169	        }
170	        /* make new_strides variable */
171	        _array_fill_strides(new_strides, new_dimensions, new_nd,
172	                            PyArray_ITEMSIZE(self), PyArray_FLAGS(self),
173	                            &(((PyArrayObject_fields *)self)->flags));
174	        memmove(PyArray_DIMS(self), new_dimensions, new_nd*sizeof(npy_intp));
175	        memmove(PyArray_STRIDES(self), new_strides, new_nd*sizeof(npy_intp));
176	    }
177	    else {
178	        npy_free_cache_dim_array(self);
179	        ((PyArrayObject_fields *)self)->nd = 0;
180	        ((PyArrayObject_fields *)self)->dimensions = NULL;
181	        ((PyArrayObject_fields *)self)->strides = NULL;
182	    }
183	    return 0;
184	}
