186	/*NUMPY_API
187	 * Resize (reallocate data).  Only works if nothing else is referencing this
188	 * array and it is contiguous.  If refcheck is 0, then the reference count is
189	 * not checked and assumed to be 1.  You still must own this data and have no
190	 * weak-references and no base object.
191	 *
192	 * On Python 3.13 and older, the check allows objects with exactly one
193	 * reference to be reallocated in-place. On Python 3.14 and newer, the array
194	 * must be uniquely referenced. In some cases this can lead to spurious
195	 * ValueErrors.
196	 *
197	 */
198	NPY_NO_EXPORT PyObject *
199	PyArray_Resize(PyArrayObject *self, PyArray_Dims *newshape, int refcheck,
200	               NPY_ORDER NPY_UNUSED(order))
201	{
202	    if (PyArray_Resize_int(self, newshape, refcheck) < 0) {
203	        return NULL;
204	    }
205	    Py_RETURN_NONE;
206	}
