226	NPY_NO_EXPORT PyObject *
227	_reshape_with_copy_arg(PyArrayObject *array, PyArray_Dims *newdims,
228	                       NPY_ORDER order, NPY_COPYMODE copy)
229	{
230	    npy_intp i;
231	    npy_intp *dimensions = newdims->ptr;
232	    PyArrayObject *ret;
233	    int ndim = newdims->len;
234	    npy_bool same;
235	    npy_intp *strides = NULL;
236	    npy_intp newstrides[NPY_MAXDIMS];
237	    int flags;
238	
239	    if (order == NPY_ANYORDER) {
240	        order = PyArray_ISFORTRAN(array) ? NPY_FORTRANORDER : NPY_CORDER;
241	    }
242	    else if (order == NPY_KEEPORDER) {
243	        PyErr_SetString(PyExc_ValueError,
244	                "order 'K' is not permitted for reshaping");
245	        return NULL;
246	    }
247	    /*  Quick check to make sure anything actually needs to be done */
248	    if (ndim == PyArray_NDIM(array) && copy != NPY_COPY_ALWAYS) {
249	        same = NPY_TRUE;
250	        i = 0;
251	        while (same && i < ndim) {
252	            if (PyArray_DIM(array, i) != dimensions[i]) {
253	                same=NPY_FALSE;
254	            }
255	            i++;
256	        }
257	        if (same) {
258	            return PyArray_View(array, NULL, NULL);
259	        }
260	    }
261	
262	    /*
263	     * fix any -1 dimensions and check new-dimensions against old size
264	     */
265	    if (_fix_unknown_dimension(newdims, array) < 0) {
266	        return NULL;
267	    }
268	    /*
269	     * Memory order doesn't depend on a copy/no-copy context.
270	     * 'order' argument is always honored.
271	     */
272	    if (copy == NPY_COPY_ALWAYS) {
273	        PyObject *newcopy = PyArray_NewCopy(array, order);
274	        if (newcopy == NULL) {
275	            return NULL;
276	        }
277	        array = (PyArrayObject *)newcopy;
278	    }
279	    else {
280	        /*
281	         * sometimes we have to create a new copy of the array
282	         * in order to get the right orientation and
283	         * because we can't just reuse the buffer with the
284	         * data in the order it is in.
285	         */
286	        Py_INCREF(array);
287	        if (((order == NPY_CORDER && !PyArray_IS_C_CONTIGUOUS(array)) ||
288	                (order == NPY_FORTRANORDER && !PyArray_IS_F_CONTIGUOUS(array)))) {
289	            int success = 0;
290	            success = _attempt_nocopy_reshape(array, ndim, dimensions,
291	                                              newstrides, order);
292	            if (success) {
293	                /* no need to copy the array after all */
294	                strides = newstrides;
295	            }
296	            else if (copy == NPY_COPY_NEVER) {
297	                PyErr_SetString(PyExc_ValueError,
298	                                "Unable to avoid creating a copy while reshaping.");
299	                Py_DECREF(array);
300	                return NULL;
301	            }
302	            else {
303	                PyObject *newcopy = PyArray_NewCopy(array, order);
304	                Py_DECREF(array);
305	                if (newcopy == NULL) {
306	                    return NULL;
307	                }
308	                array = (PyArrayObject *)newcopy;
309	            }
310	        }
311	    }
312	    /* We always have to interpret the contiguous buffer correctly */
313	
314	    /* Make sure the flags argument is set. */
315	    flags = PyArray_FLAGS(array);
316	    if (ndim > 1) {
317	        if (order == NPY_FORTRANORDER) {
318	            flags &= ~NPY_ARRAY_C_CONTIGUOUS;
319	            flags |= NPY_ARRAY_F_CONTIGUOUS;
320	        }
321	        else {
322	            flags &= ~NPY_ARRAY_F_CONTIGUOUS;
323	            flags |= NPY_ARRAY_C_CONTIGUOUS;
324	        }
325	    }
326	
327	    Py_INCREF(PyArray_DESCR(array));
328	    ret = (PyArrayObject *)PyArray_NewFromDescr_int(
329	            Py_TYPE(array), PyArray_DESCR(array),
330	            ndim, dimensions, strides, PyArray_DATA(array),
331	            flags, (PyObject *)array, (PyObject *)array,
332	            _NPY_ARRAY_ENSURE_DTYPE_IDENTITY);
333	    Py_DECREF(array);
334	    return (PyObject *)ret;
335	}
