358	/*
359	 * attempt to reshape an array without copying data
360	 *
361	 * The requested newdims are not checked, but must be compatible with
362	 * the size of self, which must be non-zero. Other than that this
363	 * function should correctly handle all reshapes, including axes of
364	 * length 1. Zero strides should work but are untested.
365	 *
366	 * If a copy is needed, returns 0
367	 * If no copy is needed, returns 1 and fills newstrides
368	 *     with appropriate strides
369	 *
370	 * The "is_f_order" argument describes how the array should be viewed
371	 * during the reshape, not how it is stored in memory (that
372	 * information is in PyArray_STRIDES(self)).
373	 *
374	 * If some output dimensions have length 1, the strides assigned to
375	 * them are arbitrary. In the current implementation, they are the
376	 * stride of the next-fastest index.
377	 */
378	static int
379	_attempt_nocopy_reshape(PyArrayObject *self, int newnd, const npy_intp *newdims,
380	                        npy_intp *newstrides, int is_f_order)
381	{
382	    int oldnd;
383	    npy_intp olddims[NPY_MAXDIMS];
384	    npy_intp oldstrides[NPY_MAXDIMS];
385	    npy_intp last_stride;
386	    int oi, oj, ok, ni, nj, nk;
387	
388	    oldnd = 0;
389	    /*
390	     * Remove axes with dimension 1 from the old array. They have no effect
391	     * but would need special cases since their strides do not matter.
392	     */
393	    for (oi = 0; oi < PyArray_NDIM(self); oi++) {
394	        if (PyArray_DIMS(self)[oi]!= 1) {
395	            olddims[oldnd] = PyArray_DIMS(self)[oi];
396	            oldstrides[oldnd] = PyArray_STRIDES(self)[oi];
397	            oldnd++;
398	        }
399	    }
400	
401	    /* oi to oj and ni to nj give the axis ranges currently worked with */
402	    oi = 0;
403	    oj = 1;
404	    ni = 0;
405	    nj = 1;
406	    while (ni < newnd && oi < oldnd) {
407	        npy_intp np = newdims[ni];
408	        npy_intp op = olddims[oi];
409	
410	        while (np != op) {
411	            if (np < op) {
412	                /* Misses trailing 1s, these are handled later */
413	                np *= newdims[nj++];
414	            } else {
415	                op *= olddims[oj++];
416	            }
417	        }
418	
419	        /* Check whether the original axes can be combined */
420	        for (ok = oi; ok < oj - 1; ok++) {
421	            if (is_f_order) {
422	                if (oldstrides[ok+1] != olddims[ok]*oldstrides[ok]) {
423	                     /* not contiguous enough */
424	                    return 0;
425	                }
426	            }
427	            else {
428	                /* C order */
429	                if (oldstrides[ok] != olddims[ok+1]*oldstrides[ok+1]) {
430	                    /* not contiguous enough */
431	                    return 0;
432	                }
433	            }
434	        }
435	
436	        /* Calculate new strides for all axes currently worked with */
437	        if (is_f_order) {
438	            newstrides[ni] = oldstrides[oi];
439	            for (nk = ni + 1; nk < nj; nk++) {
440	                newstrides[nk] = newstrides[nk - 1]*newdims[nk - 1];
441	            }
442	        }
443	        else {
444	            /* C order */
445	            newstrides[nj - 1] = oldstrides[oj - 1];
446	            for (nk = nj - 1; nk > ni; nk--) {
447	                newstrides[nk - 1] = newstrides[nk]*newdims[nk];
448	            }
449	        }
450	        ni = nj++;
451	        oi = oj++;
452	    }
453	
454	    /*
455	     * Set strides corresponding to trailing 1s of the new shape.
456	     */
457	    if (ni >= 1) {
458	        last_stride = newstrides[ni - 1];
459	    }
460	    else {
461	        last_stride = PyArray_ITEMSIZE(self);
462	    }
463	    if (is_f_order) {
464	        last_stride *= newdims[ni - 1];
465	    }
466	    for (nk = ni; nk < newnd; nk++) {
467	        newstrides[nk] = last_stride;
468	    }
469	
470	    return 1;
471	}
