473	static void
474	raise_reshape_size_mismatch(PyArray_Dims *newshape, PyArrayObject *arr)
475	{
476	    PyObject *tmp = convert_shape_to_string(newshape->len, newshape->ptr, "");
477	    if (tmp != NULL) {
478	        PyErr_Format(PyExc_ValueError,
479	                "cannot reshape array of size %zd into shape %S",
480	                PyArray_SIZE(arr), tmp);
481	        Py_DECREF(tmp);
482	    }
483	}
