485	static int
486	_fix_unknown_dimension(PyArray_Dims *newshape, PyArrayObject *arr)
487	{
488	    npy_intp *dimensions;
489	    npy_intp s_original = PyArray_SIZE(arr);
490	    npy_intp i_unknown, s_known;
491	    int i, n;
492	
493	    dimensions = newshape->ptr;
494	    n = newshape->len;
495	    s_known = 1;
496	    i_unknown = -1;
497	
498	    for (i = 0; i < n; i++) {
499	        if (dimensions[i] < 0) {
500	            if (i_unknown == -1) {
501	                i_unknown = i;
502	            }
503	            else {
504	                PyErr_SetString(PyExc_ValueError,
505	                                "can only specify one unknown dimension");
506	                return -1;
507	            }
508	        }
509	        else if (npy_mul_sizes_with_overflow(&s_known, s_known,
510	                                            dimensions[i])) {
511	            raise_reshape_size_mismatch(newshape, arr);
512	            return -1;
513	        }
514	    }
515	
516	    if (i_unknown >= 0) {
517	        if (s_known == 0 || s_original % s_known != 0) {
518	            raise_reshape_size_mismatch(newshape, arr);
519	            return -1;
520	        }
521	        dimensions[i_unknown] = s_original / s_known;
522	    }
523	    else {
524	        if (s_original != s_known) {
525	            raise_reshape_size_mismatch(newshape, arr);
526	            return -1;
527	        }
528	    }
529	    return 0;
530	}
