532	/*NUMPY_API
533	 *
534	 * return a new view of the array object with all of its unit-length
535	 * dimensions squeezed out if needed, otherwise
536	 * return the same array.
537	 */
538	NPY_NO_EXPORT PyObject *
539	PyArray_Squeeze(PyArrayObject *self)
540	{
541	    PyArrayObject *ret;
542	    npy_bool unit_dims[NPY_MAXDIMS];
543	    int idim, ndim, any_ones;
544	    npy_intp *shape;
545	
546	    ndim = PyArray_NDIM(self);
547	    shape = PyArray_SHAPE(self);
548	
549	    any_ones = 0;
550	    for (idim = 0; idim < ndim; ++idim) {
551	        if (shape[idim] == 1) {
552	            unit_dims[idim] = 1;
553	            any_ones = 1;
554	        }
555	        else {
556	            unit_dims[idim] = 0;
557	        }
558	    }
559	
560	    /* If there were no ones to squeeze out, return the same array */
561	    if (!any_ones) {
562	        Py_INCREF(self);
563	        return (PyObject *)self;
564	    }
565	
566	    ret = (PyArrayObject *)PyArray_View(self, NULL, &PyArray_Type);
567	    if (ret == NULL) {
568	        return NULL;
569	    }
570	
571	    PyArray_RemoveAxesInPlace(ret, unit_dims);
572	
573	    /*
574	     * If self isn't not a base class ndarray, call its
575	     * __array_wrap__ method
576	     */
577	    if (Py_TYPE(self) != &PyArray_Type) {
578	        PyObject *wrapped = npy_apply_wrap_simple(self, ret);
579	        Py_DECREF(ret);
580	        return wrapped;
581	    }
582	
583	    return (PyObject *)ret;
584	}
