586	/*
587	 * Just like PyArray_Squeeze, but allows the caller to select
588	 * a subset of the size-one dimensions to squeeze out.
589	 */
590	NPY_NO_EXPORT PyObject *
591	PyArray_SqueezeSelected(PyArrayObject *self, npy_bool *axis_flags)
592	{
593	    PyArrayObject *ret;
594	    int idim, ndim, any_ones;
595	    npy_intp *shape;
596	
597	    ndim = PyArray_NDIM(self);
598	    shape = PyArray_SHAPE(self);
599	
600	    /* Verify that the axes requested are all of size one */
601	    any_ones = 0;
602	    for (idim = 0; idim < ndim; ++idim) {
603	        if (axis_flags[idim] != 0) {
604	            if (shape[idim] == 1) {
605	                any_ones = 1;
606	            }
607	            else {
608	                PyErr_SetString(PyExc_ValueError,
609	                        "cannot select an axis to squeeze out "
610	                        "which has size not equal to one");
611	                return NULL;
612	            }
613	        }
614	    }
615	
616	    /* If there were no axes to squeeze out, return the same array */
617	    if (!any_ones) {
618	        Py_INCREF(self);
619	        return (PyObject *)self;
620	    }
621	
622	    ret = (PyArrayObject *)PyArray_View(self, NULL, &PyArray_Type);
623	    if (ret == NULL) {
624	        return NULL;
625	    }
626	
627	    PyArray_RemoveAxesInPlace(ret, axis_flags);
628	
629	    /*
630	     * If self isn't not a base class ndarray, call its
631	     * __array_wrap__ method
632	     */
633	    if (Py_TYPE(self) != &PyArray_Type) {
634	        PyObject *wrapped = npy_apply_wrap_simple(self, ret);
