758	/*
759	 * Sorts items so stride is descending, because C-order
760	 * is the default in the face of ambiguity.
761	 */
762	static int _npy_stride_sort_item_comparator(const void *a, const void *b)
763	{
764	    npy_intp astride = ((const npy_stride_sort_item *)a)->stride,
765	            bstride = ((const npy_stride_sort_item *)b)->stride;
766	
767	    /* Sort the absolute value of the strides */
768	    if (astride < 0) {
769	        astride = -astride;
770	    }
771	    if (bstride < 0) {
772	        bstride = -bstride;
773	    }
774	
775	    if (astride == bstride) {
776	        /*
777	         * Make the qsort stable by next comparing the perm order.
778	         * (Note that two perm entries will never be equal)
779	         */
780	        npy_intp aperm = ((const npy_stride_sort_item *)a)->perm,
781	                bperm = ((const npy_stride_sort_item *)b)->perm;
782	        return (aperm < bperm) ? -1 : 1;
783	    }
784	    if (astride > bstride) {
785	        return -1;
786	    }
787	    return 1;
788	}
