797	NPY_NO_EXPORT void
798	PyArray_CreateSortedStridePerm(int ndim, npy_intp const *strides,
799	                        npy_stride_sort_item *out_strideperm)
800	{
801	    int i;
802	
803	    /* Set up the strideperm values */
804	    for (i = 0; i < ndim; ++i) {
805	        out_strideperm[i].perm = i;
806	        out_strideperm[i].stride = strides[i];
807	    }
808	
809	    /* Sort them */
810	    qsort(out_strideperm, ndim, sizeof(npy_stride_sort_item),
811	                                    &_npy_stride_sort_item_comparator);
