822	/*
823	 * Creates a sorted stride perm matching the KEEPORDER behavior
824	 * of the NpyIter object. Because this operates based on multiple
825	 * input strides, the 'stride' member of the npy_stride_sort_item
826	 * would be useless and we simply argsort a list of indices instead.
827	 *
828	 * The caller should have already validated that 'ndim' matches for
829	 * every array in the arrays list.
830	 */
831	NPY_NO_EXPORT void
832	PyArray_CreateMultiSortedStridePerm(int narrays, PyArrayObject **arrays,
833	                        int ndim, int *out_strideperm)
834	{
835	    int i0, i1, ipos, ax_j0, ax_j1, iarrays;
836	
837	    /* Initialize the strideperm values to the identity. */
838	    for (i0 = 0; i0 < ndim; ++i0) {
839	        out_strideperm[i0] = i0;
840	    }
841	
842	    /*
843	     * This is the same as the custom stable insertion sort in
844	     * the NpyIter object, but sorting in the reverse order as
845	     * in the iterator. The iterator sorts from smallest stride
846	     * to biggest stride (Fortran order), whereas here we sort
847	     * from biggest stride to smallest stride (C order).
848	     */
849	    for (i0 = 1; i0 < ndim; ++i0) {
850	
851	        ipos = i0;
852	        ax_j0 = out_strideperm[i0];
853	
854	        for (i1 = i0 - 1; i1 >= 0; --i1) {
855	            int ambig = 1, shouldswap = 0;
856	
857	            ax_j1 = out_strideperm[i1];
858	
859	            for (iarrays = 0; iarrays < narrays; ++iarrays) {
860	                if (PyArray_SHAPE(arrays[iarrays])[ax_j0] != 1 &&
861	                            PyArray_SHAPE(arrays[iarrays])[ax_j1] != 1) {
862	                    if (s_intp_abs(PyArray_STRIDES(arrays[iarrays])[ax_j0]) <=
863	                            s_intp_abs(PyArray_STRIDES(arrays[iarrays])[ax_j1])) {
864	                        /*
865	                         * Set swap even if it's not ambiguous already,
866	                         * because in the case of conflicts between
867	                         * different operands, C-order wins.
868	                         */
869	                        shouldswap = 0;
870	                    }
871	                    else {
872	                        /* Only set swap if it's still ambiguous */
873	                        if (ambig) {
874	                            shouldswap = 1;
875	                        }
876	                    }
877	
878	                    /*
879	                     * A comparison has been done, so it's
880	                     * no longer ambiguous
881	                     */
882	                    ambig = 0;
883	                }
884	            }
885	            /*
886	             * If the comparison was unambiguous, either shift
887	             * 'ipos' to 'i1' or stop looking for an insertion point
888	             */
889	            if (!ambig) {
890	                if (shouldswap) {
891	                    ipos = i1;
892	                }
893	                else {
894	                    break;
895	                }
896	            }
897	        }
898	
899	        /* Insert out_strideperm[i0] into the right place */
900	        if (ipos != i0) {
901	            for (i1 = i0; i1 > ipos; --i1) {
902	                out_strideperm[i1] = out_strideperm[i1-1];
903	            }
904	            out_strideperm[ipos] = ax_j0;
905	        }
906	    }
907	}
