909	/*NUMPY_API
910	 * Ravel
911	 * Returns a contiguous array
912	 */
913	NPY_NO_EXPORT PyObject *
914	PyArray_Ravel(PyArrayObject *arr, NPY_ORDER order)
915	{
916	    PyArray_Dims newdim = {NULL,1};
917	    npy_intp val[1] = {-1};
918	
919	    newdim.ptr = val;
920	
921	    if (order == NPY_KEEPORDER) {
922	        /* This handles some corner cases, such as 0-d arrays as well */
923	        if (PyArray_IS_C_CONTIGUOUS(arr)) {
924	            order = NPY_CORDER;
925	        }
926	        else if (PyArray_IS_F_CONTIGUOUS(arr)) {
927	            order = NPY_FORTRANORDER;
928	        }
929	    }
930	    else if (order == NPY_ANYORDER) {
931	        order = PyArray_ISFORTRAN(arr) ? NPY_FORTRANORDER : NPY_CORDER;
932	    }
933	
934	    if (order == NPY_CORDER && PyArray_IS_C_CONTIGUOUS(arr)) {
935	        return PyArray_Newshape(arr, &newdim, NPY_CORDER);
936	    }
937	    else if (order == NPY_FORTRANORDER && PyArray_IS_F_CONTIGUOUS(arr)) {
938	        return PyArray_Newshape(arr, &newdim, NPY_FORTRANORDER);
939	    }
940	    /* For KEEPORDER, check if we can make a flattened view */
941	    else if (order == NPY_KEEPORDER) {
942	        npy_stride_sort_item strideperm[NPY_MAXDIMS];
943	        npy_intp stride;
944	        int i, ndim = PyArray_NDIM(arr);
945	
946	        PyArray_CreateSortedStridePerm(PyArray_NDIM(arr),
947	                                PyArray_STRIDES(arr), strideperm);
948	
949	        /* The output array must be contiguous, so the first stride is fixed */
950	        stride = PyArray_ITEMSIZE(arr);
951	
952	        for (i = ndim-1; i >= 0; --i) {
953	            if (PyArray_DIM(arr, strideperm[i].perm) == 1) {
954	                /* A size one dimension does not matter */
955	                continue;
956	            }
957	            if (strideperm[i].stride != stride) {
958	                break;
959	            }
960	            stride *= PyArray_DIM(arr, strideperm[i].perm);
961	        }
962	
963	        /* If all the strides matched a contiguous layout, return a view */
964	        if (i < 0) {
965	            stride = PyArray_ITEMSIZE(arr);
966	            val[0] = PyArray_SIZE(arr);
967	
968	            Py_INCREF(PyArray_DESCR(arr));
969	            return PyArray_NewFromDescrAndBase(
970	                    Py_TYPE(arr), PyArray_DESCR(arr),
971	                    1, val, &stride, PyArray_BYTES(arr),
972	                    PyArray_FLAGS(arr), (PyObject *)arr, (PyObject *)arr);
973	        }
974	    }
975	
976	    return PyArray_Flatten(arr, order);
977	}
