979	/*NUMPY_API
980	 * Flatten
981	 */
982	NPY_NO_EXPORT PyObject *
983	PyArray_Flatten(PyArrayObject *a, NPY_ORDER order)
984	{
985	    PyArrayObject *ret;
986	    npy_intp size;
987	
988	    if (order == NPY_ANYORDER) {
989	        order = PyArray_ISFORTRAN(a) ? NPY_FORTRANORDER : NPY_CORDER;
990	    }
991	
992	    size = PyArray_SIZE(a);
993	    Py_INCREF(PyArray_DESCR(a));
994	    ret = (PyArrayObject *)PyArray_NewFromDescr(Py_TYPE(a),
995	                               PyArray_DESCR(a),
996	                               1, &size,
997	                               NULL,
998	                               NULL,
999	                               0, (PyObject *)a);
1000	    if (ret == NULL) {
1001	        return NULL;
1002	    }
1003	
