1013	 *
1014	 * Removes the axes flagged as True from the array,
1015	 * modifying it in place. If an axis flagged for removal
1016	 * has a shape entry bigger than one, this effectively selects
1017	 * index zero for that axis.
1018	 *
1019	 * WARNING: If an axis flagged for removal has a shape equal to zero,
1020	 *          the array will point to invalid memory. The caller must
1021	 *          validate this!
1022	 *          If an axis flagged for removal has a shape larger than one,
1023	 *          the aligned flag (and in the future the contiguous flags),
1024	 *          may need explicit update.
1025	 *
1026	 * For example, this can be used to remove the reduction axes
1027	 * from a reduction result once its computation is complete.
1028	 */
1029	NPY_NO_EXPORT void
1030	PyArray_RemoveAxesInPlace(PyArrayObject *arr, const npy_bool *flags)
1031	{
1032	    PyArrayObject_fields *fa = (PyArrayObject_fields *)arr;
1033	    npy_intp *shape = fa->dimensions, *strides = fa->strides;
1034	    int idim, ndim = fa->nd, idim_out = 0;
