1036	    /* Compress the dimensions and strides */
1037	    for (idim = 0; idim < ndim; ++idim) {
1038	        if (!flags[idim]) {
1039	            shape[idim_out] = shape[idim];
1040	            strides[idim_out] = strides[idim];
1041	            ++idim_out;
1042	        }
1043	    }
1044	
1045	    /* The final number of dimensions */
1046	    fa->nd = idim_out;
